const axios = require("axios");
const baseURL = "https://shubhdeeps.github.io/e-numbers/Data/Enumbers.json"


const getData = (setData) => {

        axios
          .get(baseURL)
          .then(response => {
            console.log('promise fulfilled')
            setData(response.data)
          })
      
}

export default { 
    getData: getData
  }